import{_ as t,o as l,c as a,f as n}from"./chunks/framework.DoXE6-or.js";const h=JSON.parse('{"title":"Archlinux + hyprland初次使用记录","description":"","frontmatter":{"layout":"post","title":"Archlinux + hyprland初次使用记录","date":"2025-11-18T05:18:47.000Z","tags":["OS","Linux"],"class":"记录","image_url":"https://enhiucyodopknrbdtswy.supabase.co/storage/v1/object/public/resources/img/89596288_p0.png","summary":null,"top":true},"headers":[{"level":2,"title":"我为什么选择Linux","slug":"我为什么选择linux","link":"#我为什么选择linux","children":[]},{"level":2,"title":"安装","slug":"安装","link":"#安装","children":[{"level":3,"title":"使用设备","slug":"使用设备","link":"#使用设备","children":[]}]}],"relativePath":"posts/newtoarch.md","filePath":"posts/newtoarch.md"}'),i={name:"posts/newtoarch.md"};function o(r,e,s,u,c,p){return l(),a("div",null,[...e[0]||(e[0]=[n('<h2 id="我为什么选择linux" tabindex="-1">我为什么选择Linux <a class="header-anchor" href="#我为什么选择linux" aria-label="Permalink to &quot;我为什么选择Linux&quot;">​</a></h2><p>在开发过程中，我经常察觉，windows光是系统服务就已经占用我<strong>内存</strong>的50%了（16G），剩下的用于调试经常不够用。正巧我的磁盘也满了，懒得整理，我决定重装系统进一步验证。结果不出所料，一个全新的windows11，CPU平均每秒20%，内存45%。不排除我的硬件很拉，但是看着后台满满的服务列表，确实很头疼。</p><p>除此之外，相信很多人都有过<strong>磁盘空间不足</strong>的烦恼，我也不例外。以前不懂电脑的我，面对逐渐杂乱无章的桌面和完全看不懂的系统文件，在不使用专门的软件的情况下，只能选择周期性地重置系统。但每次重新开始，都没有一个很好的管理文件的方式。直到成为程序员之后的某一天，我决定这是我最后一次用重置系统来解决问题。</p><p>于是，出于减少内存占用、学习手动管理系统、获得更自由的系统美化、<s>转移最近的焦虑情绪</s>等目的，我想尝试着学习linux系统。</p><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><p>问GPT给我推荐的一些Linux发行版，和b站评论的推荐中，我最终选择了Archlinux挑战一下自己。</p><p>安装过程是一次前所未有的体验。目标是将linux安装到固态移动硬盘里，C盘保留win11。</p><h3 id="使用设备" tabindex="-1">使用设备 <a class="header-anchor" href="#使用设备" aria-label="Permalink to &quot;使用设备&quot;">​</a></h3><blockquote><ol><li>Dell G15 笔记本</li><li>三星T7移动固态硬盘</li><li>128G U盘</li><li>魔法手机</li></ol></blockquote><p>To be continued</p>',10)])])}const _=t(i,[["render",o]]);export{h as __pageData,_ as default};
